        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
